import { forwardRef } from "react";
import type { LabelHTMLAttributes, ReactNode } from "react";
import { Slot } from "@radix-ui/react-slot";
import * as styles from "./Label.css";
import type { LabelVariant } from "./Label.config";
import { DEFAULT_LABEL_VARIANT } from "./Label.config";
import { clsx } from "clsx";

export interface LabelCustomProps {
  /**
   * The label text
   */
  children: ReactNode;

  /**
   * Whether the field is required (shows asterisk)
   */
  required?: boolean;

  /**
   * The visual variant of the label
   * @default "bold"
   */
  variant?: LabelVariant;

  /**
   * When true, the component will render its child element instead of the default
   * `<label>` element, merging the Label's props and behavior onto the child.
   *
   * This is useful when integrating with component libraries like react-aria that
   * require their own label components for accessibility.
   *
   * @example
   * // Using with react-aria-components TextField
   * <Label asChild>
   *   <AriaLabel>Email address</AriaLabel>
   * </Label>
   *
   * @default false
   */
  asChild?: boolean;
}

export interface LabelProps
  extends
    Omit<LabelHTMLAttributes<HTMLLabelElement>, keyof LabelCustomProps>,
    LabelCustomProps {}

export const Label = forwardRef<HTMLLabelElement, LabelProps>(
  (
    {
      children,
      required = false,
      variant = DEFAULT_LABEL_VARIANT,
      asChild = false,
      className,
      ...props
    },
    ref
  ) => {
    const labelClassName = clsx(
      styles.labelTitle({ variant, required }),
      className
    );

    const Component = asChild ? Slot : "label";

    return (
      <Component
        ref={ref}
        className={labelClassName}
        {...(required && { "data-required": true })}
        {...props}
      >
        {children}
      </Component>
    );
  }
);

Label.displayName = "Label";
